INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Threaded web archive$q$, $q$Browse mailing list history organized by conversation thread rather than flat chronological dumps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Full-text search$q$, $q$Search across message subjects and bodies within and across lists.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Reply and post from browser$q$, $q$Authenticated users can start new threads or reply to existing messages without an email client.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Favorites$q$, $q$Mark messages as favorites for quick reference later.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Standalone forum mode$q$, $q$Run HyperKitty independently of Mailman Core as a lightweight web forum.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$REST archiver API integration$q$, $q$Receives message data from Mailman Core via a documented archiver API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Multi-list, multi-domain support$q$, $q$Archive many mailing lists and virtual-host domains from a single install.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Open API$q$, $q$Developers can build integrations against HyperKitty's own API for custom tooling.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Completely free and open source with no licensing fees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Modern, searchable threaded interface that is a major usability upgrade over Pipermail.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Full data ownership since it is self-hosted.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Deep integration with the rest of the Mailman 3 ecosystem, including Postorius and Mailman Core.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Active community maintenance and packaging across major Linux distributions.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Requires technical expertise to install, configure and maintain a full Mailman 3 stack.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$No official managed or hosted SaaS offering from the project itself.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$No built-in enterprise support, SLAs or customer success team.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$UI is functional but not as polished or customizable as modern SaaS community platforms.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Setup involving a database, search backend and web server is more involved than a one-click SaaS signup.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Is HyperKitty free to use?$q$, $q$Yes. HyperKitty is released as free, open-source software and can be self-hosted at no licensing cost, though you are responsible for your own server infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Do I need Mailman to use HyperKitty?$q$, $q$Normally HyperKitty is deployed alongside Mailman Core and Postorius as part of the Mailman 3 suite, but it can also run in a standalone mode as an independent web forum.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$What replaced Pipermail?$q$, $q$HyperKitty is the modern, threaded, searchable replacement for Mailman's older Pipermail archiver.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Can I search across multiple mailing lists at once?$q$, $q$Yes, HyperKitty supports full-text search within individual lists and across the lists hosted on an installation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Who maintains HyperKitty?$q$, $q$It is maintained by the GNU Mailman open-source community, with its origins tied to work by Red Hat developer Aurelien Bompard for the Fedora Project.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Is there a hosted version of HyperKitty?$q$, $q$The core project does not offer an official hosted SaaS product, though some third-party providers offer managed Mailman and HyperKitty hosting.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Open-source project mailing list archives$q$, $q$Projects like Fedora and other GNU and free-software communities use HyperKitty to give contributors a searchable, threaded public record of technical discussions.$q$, $q$Open-source software maintainers and communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$University and research mailing lists$q$, $q$Departments and research groups self-host HyperKitty to archive faculty, student and working-group discussion lists with searchable history.$q$, $q$Academic institutions and research groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Standards-body and community discussion archives$q$, $q$Organizations coordinating technical standards or community governance via mailing lists use HyperKitty as the public record of debate and decisions.$q$, $q$Standards organizations and community governance groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Self-Hosted (Community Edition)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full HyperKitty source code","Unlimited mailing lists and archives","Self-managed infrastructure","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$Third-Party Managed Hosting$q$, $q$Varies by provider$q$, $q$Custom$q$, NULL, $q$["Mailman 3 and HyperKitty hosted by a third-party provider","Infrastructure and upgrades managed for you","Optional support contracts","Pricing set independently by each hosting provider"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HyperKitty is the official web-based archiver for GNU Mailman 3, the free and open-source mailing list manager maintained under the GNU Project. It replaces Mailman's legacy Pipermail archiver with a modern, Django-powered interface that presents mailing list history as threaded conversations rather than flat chronological text dumps, and lets authenticated users reply to or start new threads directly from a browser instead of an email client.$q$, $q$The project originated around 2012 through work led by Aurelien Bompard, a developer hired by Red Hat to work on Fedora Project infrastructure, with early contributions also coming through a 2012 Google Summer of Code proposal. It has since become the default archiver bundled with the Mailman 3 suite, working alongside Mailman Core, for message delivery and list management, and Postorius, for web-based list administration.$q$, $q$There is no company behind HyperKitty. It is fully open-source, released under GPL-family licensing consistent with the GNU Mailman project, and distributed through GitLab, PyPI and the package repositories of major Linux distributions such as Debian, Fedora and Arch Linux.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HyperKitty's core value is turning raw mailing list traffic into a searchable, threaded, browsable archive. Messages received by Mailman Core are pushed to HyperKitty through a REST-based archiver API, stored in a relational database, and indexed for full-text search, letting users find specific discussions across potentially years of list history without downloading mbox files.$q$, $q$Beyond passive archiving, HyperKitty supports interactive participation: users can favorite messages, start new threads, and reply to existing ones from the web interface, effectively functioning as a lightweight forum layered on top of traditional email lists. It can even run in a standalone mode without the rest of Mailman, serving purely as a web forum.$q$, $q$Because it is open-source, HyperKitty can be self-hosted for a single list, a whole organization's list infrastructure, or a large multi-domain deployment like Fedora's, giving operators complete control over data retention, moderation and branding.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HyperKitty carries no license fee. It is free, open-source software, and the only real cost to running it is the infrastructure, typically a database, a search backend, a WSGI-capable web server, and administrative time, needed to self-host the full Mailman 3 stack.$q$, $q$Organizations that do not want to manage that infrastructure themselves can turn to third-party providers who offer managed Mailman and HyperKitty hosting, though pricing for these services is set independently by each provider rather than by the HyperKitty project itself, since no official managed SaaS product exists.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11597642-219f-4d25-9f31-8486b2b24eba', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Configure-Price-Quote (CPQ)$q$, $q$Sales teams build, approve and e-sign quotes inside the platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Subscription and usage-based billing$q$, $q$Supports flat, tiered, seat-based and metered consumption pricing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Automated invoicing and dunning$q$, $q$Compliant invoice generation, tax handling and retry logic for failed payments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Multi-PSP payment orchestration$q$, $q$Routes payments across Stripe, GoCardless, Mollie and Airwallex.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Real-time usage tracking$q$, $q$Ingest unlimited billing events and meter consumption as it happens.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Revenue recognition and reporting$q$, $q$Built-in analytics and financial reporting for recurring revenue metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Customer self-service portal$q$, $q$Lets end customers view invoices, update payment methods and manage subscriptions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Prepaid credits and seat management$q$, $q$Handles prepaid credit balances and automated seat-based billing adjustments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Combines CPQ, billing, payments and revenue recognition in one connected workflow.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Transparent, publicly published pricing rather than sales-gated quotes.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Payment-processor flexibility across four major PSPs instead of vendor lock-in.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Purpose-built for usage-based and hybrid pricing models that many legacy billing tools handle poorly.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Backed by well-known SaaS-focused investors with founders drawn from the Qonto, Spendesk and Primer network.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Revenue-percentage-based pricing, 0.6 to 0.7 percent of billed revenue, can get expensive at scale compared to flat-fee competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Relatively young company, founded in 2022, with a shorter track record than incumbents like Chargebee or Zuora.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$CRM and accounting integrations carry an additional per-integration monthly fee.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Smaller team size than larger, established billing platforms may mean a leaner support organization.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$High-volume enterprise pricing is custom and not published, requiring a sales conversation.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$What does Hyperline do?$q$, $q$Hyperline is a quote-to-cash platform that combines CPQ, subscription billing, invoicing, payment orchestration and usage-based billing for B2B software companies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$How much does Hyperline cost?$q$, $q$Plans start at $199 per month plus 0.6 percent of billed revenue for the core Quote to Cash plan, rising to $299 per month plus 0.7 percent for usage-based billing, with custom pricing above $5 million in ARR.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Does Hyperline offer a free trial?$q$, $q$Yes, Hyperline offers a self-serve free trial covering your first 10 invoices with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Which payment processors does Hyperline support?$q$, $q$Hyperline natively integrates with Stripe, GoCardless, Mollie and Airwallex.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Who founded Hyperline?$q$, $q$Hyperline was founded in Paris in 2022 by Lucas Bedout and Clement Garbay.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Is Hyperline suitable for usage-based pricing models?$q$, $q$Yes, its Quote to Cash plus Usage plan is built specifically for metered, seat-based and consumption pricing with real-time tracking.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Scaling B2B SaaS billing operations$q$, $q$Replacing spreadsheets or ad hoc invoicing with automated subscription billing, tax handling and dunning as a company grows past its early customers.$q$, $q$Finance and RevOps teams at growth-stage SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Usage-based and consumption pricing$q$, $q$Metering API calls, seats or other consumption units in real time and billing customers automatically based on actual usage.$q$, $q$Infrastructure and usage-priced software companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Sales-to-invoice workflow automation$q$, $q$Letting sales reps generate, approve and e-sign quotes that flow directly into subscriptions and invoices without manual handoffs to finance.$q$, $q$Sales operations and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Quote to Cash$q$, $q$$199/month + 0.6% of billed revenue$q$, $q$Monthly$q$, NULL, $q$["Subscriptions","CPQ with e-signature","Compliant invoicing","Payment collection","Tax management","Customer portal","Analytics","International billing","10-invoice free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Quote to Cash + Usage$q$, $q$$299/month + 0.7% of billed revenue$q$, $q$Monthly$q$, NULL, $q$["Everything in Quote to Cash","Unlimited billing events","Real-time consumption tracking","Metered products","Automated seat-based billing","Prepaid credit management","Direct database connection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$Quote to Cash + High Volume$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["For companies over $5M ARR","Unlimited invoices","Premium support","Migration and onboarding","Historical data import"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hyperline is a quote-to-cash revenue management platform for B2B software companies, combining configure-price-quote, subscription billing, invoicing, payment collection and usage-based billing in one connected system. It was founded in Paris in 2022 by Lucas Bedout and Clement Garbay and launched publicly in June 2023.$q$, $q$The company has raised roughly $14.4 million in disclosed funding, including a EUR4 million seed round and a later $10 million seed extension, both led by Index Ventures, with participation from Kima Ventures and angel investors tied to Qonto, Spendesk and Primer.$q$, $q$As of 2026 Hyperline is reported to have grown to around 25-35 employees, up from roughly 14 in early 2025, reflecting continued expansion of its Paris-based team since the funding extension.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hyperline's CPQ module lets sales teams build, approve and e-sign quotes without leaving the platform, and those quotes flow directly into subscriptions and invoices rather than requiring a manual handoff to finance.$q$, $q$On the billing side, Hyperline handles compliant invoicing, tax calculation, dunning for failed payments and revenue recognition, while its payments layer orchestrates transactions across Stripe, GoCardless, Mollie and Airwallex so companies are not locked into a single processor.$q$, $q$For usage-based and hybrid pricing models, Hyperline supports unlimited billing events, real-time consumption tracking, metered products, automated seat-based billing and prepaid credit management, addressing a segment that many legacy subscription-billing tools handle poorly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hyperline publishes its pricing openly, which is unusual for CPQ and billing vendors. The entry Quote to Cash plan costs $199 per month plus 0.6 percent of billed revenue, while the Quote to Cash plus Usage plan, which adds real-time consumption tracking and metered billing, costs $299 per month plus 0.7 percent of billed revenue.$q$, $q$Both self-serve tiers include a free trial covering the first 10 invoices with no credit card required, and can add CRM or accounting-system integrations for an extra $50 per integration per month. Companies above $5 million in annual recurring revenue move to a custom Quote to Cash plus High Volume contract with unlimited invoices and dedicated migration support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d452fd91-6d49-40e7-8a71-ae9f6a9bbf92', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Multi-region uptime monitoring$q$, $q$Checks run from around 18-19 global locations with 20-30 second intervals on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Branded status pages$q$, $q$Public or private status pages on a custom domain to communicate incidents to customers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$On-call scheduling and escalation$q$, $q$Rotating on-call schedules with time-based escalation to a backup responder.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Multi-channel alerting$q$, $q$Notifications via Slack, SMS, phone call, email, PagerDuty and OpsGenie.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Synthetic and browser checks$q$, $q$Playwright-based checks that simulate real user flows, not just simple pings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Broad monitor types$q$, $q$HTTP and HTTPS, API, SSL certificate, cron and heartbeat, TCP, ICMP and DNS monitoring.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Server agents$q$, $q$Lightweight agents for monitoring server-level metrics alongside external endpoint checks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Auto-retry verification$q$, $q$Re-checks failing endpoints from multiple regions before firing an alert, reducing false positives.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Free plan with 20 monitors, unusually generous for a no-cost tier.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Pricing scales by monitor count, not per-seat, which keeps costs predictable for growing teams.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$EU-based data hosting appeals to teams with GDPR or data-residency requirements.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$On-call and escalation features are included even on lower-cost paid plans, unlike many competitors that gate them behind enterprise tiers.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Bootstrapped and independently owned, with no VC pressure pushing aggressive price increases.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Free plan is limited to 5-minute check intervals and a single basic status page.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Smaller company than category leaders like Better Stack or Pingdom, which may mean fewer integrations or slower feature velocity.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Higher-frequency checks and advanced features require moving up to paid tiers.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Additional seats on the Business plan add incremental monthly cost.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Enterprise-scale monitoring requires a custom quote rather than transparent published pricing.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Is Hyperping free to use?$q$, $q$Yes, Hyperping has a free-forever plan with 20 monitors, one basic status page and 5-minute check intervals.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$How often does Hyperping check my endpoints?$q$, $q$Check frequency ranges from every 5 minutes on the free plan down to every 20 seconds on the Business plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Does Hyperping support on-call scheduling?$q$, $q$Yes, on-call scheduling and escalation policies are included starting on the Essentials paid plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Where is Hyperping's data hosted?$q$, $q$Hyperping stores customer data in EU data centers, specifically Frankfurt, Germany.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Who founded Hyperping?$q$, $q$Hyperping was founded in Paris, France in 2017 by Leo Baecker, and remains bootstrapped without outside venture funding.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$What alert channels does Hyperping support?$q$, $q$Hyperping can alert teams via Slack, SMS, phone calls, email, PagerDuty, OpsGenie and webhooks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$SaaS uptime monitoring$q$, $q$Startups and SaaS teams monitor production endpoints, APIs and background jobs to catch outages before customers report them.$q$, $q$SaaS engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Public status page communication$q$, $q$Companies publish a branded, custom-domain status page so customers and stakeholders can self-serve incident status instead of contacting support.$q$, $q$Customer support and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$On-call incident response$q$, $q$Engineering teams set up rotating on-call schedules with escalation policies so critical alerts always reach a responder.$q$, $q$Site reliability and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Free$q$, $q$$0$q$, $q$Forever$q$, NULL, $q$["20 monitors","5-minute checks","1 basic status page","1 server agent","1 seat"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Essentials$q$, $q$$29/month$q$, $q$Billed annually$q$, NULL, $q$["50 monitors","30-second checks","Custom domain status page","5 server agents","On-call and escalation policies","2 seats","All integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Pro$q$, $q$$89/month$q$, $q$Billed annually$q$, NULL, $q$["100 monitors","20 server agents","10 browser checks","3 status pages","Phone call alerts","5 seats"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$Business$q$, $q$$299/month$q$, $q$Billed annually$q$, NULL, $q$["1,000 monitors","20-second checks","100 server agents","25 browser checks","10 status pages","SAML SSO","Audit logs","15 seats included"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hyperping is a bootstrapped uptime monitoring and status page platform founded in Paris in 2017 by Leo Baecker. It has grown without venture capital funding, remaining a small, independently owned French company with no outside investors.$q$, $q$The platform stores customer data in EU data centers in Frankfurt and runs checks from a global network of roughly 18-19 regions, with intervals as frequent as every 20-30 seconds on paid plans and automatic retry verification to cut down on false-positive alerts.$q$, $q$Hyperping combines three pillars in one product: synthetic and uptime monitoring, branded status pages, and on-call scheduling with escalation policies, rather than treating incident communication and on-call response as separate add-on products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Monitoring coverage is broad, spanning HTTP and HTTPS, API, SSL certificate expiry, cron job and heartbeat checks, Playwright-based browser checks, TCP port, ICMP ping and DNS monitoring, giving teams a single tool for most external monitoring needs.$q$, $q$Status pages can be hosted on a custom domain and are included even on Hyperping's lower-cost paid plans, letting teams communicate incidents to customers without a separate status-page subscription.$q$, $q$On-call scheduling supports escalation chains that page a backup responder over a different channel if the primary on-call engineer does not acknowledge an alert within a set time window, with alerts deliverable via Slack, SMS, phone call, PagerDuty, OpsGenie, email and webhooks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hyperping charges based on the number of monitors rather than the number of team members, which keeps costs more predictable as a team grows. The Free plan includes 20 monitors, 5-minute checks and one basic status page at no cost, while the Essentials plan starts at $29 per month billed annually with 50 monitors and 30-second checks.$q$, $q$Higher tiers, Pro at $89 per month and Business at $299 per month, both billed annually, add more monitors, more frequent checks, additional status pages, SAML SSO and audit logs, with an Enterprise tier available for custom limits and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d916b89-9e14-4c8b-b458-9c5fbc97233a', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Cross-framework control mapping$q$, $q$Map one control or evidence artifact to multiple frameworks such as SOC 2, ISO 27001 and GDPR to avoid duplicate work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Automated evidence collection$q$, $q$Integrations with AWS, Azure, Google Cloud, Okta and other systems continuously pull compliance evidence.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$User Access Review automation$q$, $q$Automates periodic access certification across cloud and identity systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Risk register and assessment$q$, $q$Identify, score and track organizational and third-party risks in one workspace.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Vendor and third-party risk management$q$, $q$Assess and monitor vendor security posture through the Mitigate module.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Audit management and collaboration$q$, $q$Give external auditors direct, controlled access to evidence inside the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Pre-built framework templates$q$, $q$Starter templates for common frameworks reduce setup time for new certifications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$AI-assisted compliance workflows$q$, $q$AI features help validate evidence, draft questionnaire responses and surface risk insights.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Strong cross-framework control mapping reduces duplicate evidence-gathering work for organizations managing multiple certifications.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Combines compliance management and risk and vendor management in a single platform rather than requiring separate tools.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Deep integrations with major cloud and identity providers automate much of the manual evidence-chasing.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Well capitalized with over $77 million raised, suggesting continued product investment.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Strong reported customer satisfaction around automation and customer support in third-party reviews.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Pricing is not published and requires a sales conversation, making it harder to budget upfront.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$No free trial and a mandatory implementation fee add to the upfront cost.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Some users report the interface feels overwhelming, particularly when drilling into control mappings or risk modules.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Median contract value, reported around $40,000 per year, puts it out of reach for very small startups.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Newer modules like UAR and AI features are still maturing relative to core compliance workflows.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$What frameworks does Hyperproof support?$q$, $q$Hyperproof supports common frameworks including SOC 2, ISO 27001, GDPR, HIPAA, PCI DSS and NIST, with pre-built templates and cross-framework control mapping.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$How much does Hyperproof cost?$q$, $q$Hyperproof does not publish pricing publicly; it sells through three tiers, Professional, Business and Enterprise, with third-party estimates putting entry contracts around $12,000 per year and median deals around $40,000 per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Does Hyperproof offer a free trial?$q$, $q$No, Hyperproof does not offer a self-serve free trial; access requires a sales engagement and typically a paid implementation.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Who founded Hyperproof?$q$, $q$Hyperproof was founded in 2018 by Craig Unger and is headquartered in Bellevue, Washington.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$What is the Hyperproof UAR module?$q$, $q$The User Access Review module automates periodic access certification checks across systems like AWS, Azure, Google Cloud and Okta.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Who are Hyperproof's main competitors?$q$, $q$Hyperproof competes primarily with Vanta, Drata, Secureframe, OneTrust and LogicGate in the GRC and compliance-automation space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Multi-framework compliance management$q$, $q$Security and compliance teams managing SOC 2, ISO 27001 and other certifications simultaneously use Hyperproof to map shared controls and avoid duplicate evidence collection.$q$, $q$Compliance and security teams at mid-market and enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Vendor and third-party risk assessment$q$, $q$Procurement and security teams assess and continuously monitor the risk posture of vendors and suppliers through Hyperproof's Mitigate module.$q$, $q$Vendor risk and procurement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Continuous audit readiness$q$, $q$Organizations preparing for recurring external audits use Hyperproof to keep evidence current year-round instead of scrambling before each audit cycle.$q$, $q$Internal audit and IT governance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Professional$q$, $q$Custom (est. from ~$12,000/year)$q$, $q$Annual$q$, NULL, $q$["Pre-built framework templates","Unlimited users","Core compliance management","Standard integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Business$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Everything in Professional","Expanded framework and workflow support","Risk management module","Enhanced integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Everything in Business","Advanced risk and vendor management","Premium support","Dedicated onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hyperproof is a cloud-based governance, risk and compliance platform that automates the ongoing work of maintaining compliance across frameworks like SOC 2, ISO 27001, GDPR, HIPAA and PCI DSS. It was founded in 2018 by Craig Unger and is headquartered in Bellevue, Washington.$q$, $q$The company has raised approximately $77.3 million in total funding, including a $40 million round led by Riverwood Capital with participation from Toba Capital, and reports roughly 175-180 employees as of 2026.$q$, $q$Hyperproof is organized around two connected modules: Comply, for continuous compliance management and audit readiness, and Mitigate, for risk and third-party vendor risk management, unified in a single workspace so controls can be mapped once and reused across overlapping frameworks.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A core differentiator is cross-framework control mapping, which lets a single piece of evidence satisfy requirements in multiple frameworks at once, for example covering both a SOC 2 control and an equivalent ISO 27001 control, reducing duplicate evidence-gathering work.$q$, $q$Automated evidence collection integrates with cloud infrastructure and identity providers including AWS, Azure, Google Cloud and Okta, and a dedicated User Access Review module automates periodic access certification checks that would otherwise require hundreds of manual steps.$q$, $q$The platform also includes a risk register, vendor and third-party risk assessment workflows, pre-built framework templates, direct auditor collaboration tools, and newer AI-assisted features for evidence validation and questionnaire responses.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hyperproof does not publish pricing publicly. It sells through three tiers, Professional, Business and Enterprise, all including unlimited users and pre-built framework templates, with the differences driven by the number of supported frameworks, workflow sophistication and support level.$q$, $q$Third-party pricing trackers estimate Professional-tier contracts starting around $12,000 per year, with median deals in the $40,000-$44,000 per year range, plus a separate one-time implementation fee typically between $10,000 and $30,000; there is no self-serve free trial.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0412c80c-5647-4376-b362-9ccece4ef8e5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$TypeAhead autocomplete$q$, $q$Inline, Tab-to-accept sentence completion embedded across the browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$AI chat assistant$q$, $q$Conversational assistant for brainstorming, drafting and editing content anywhere online.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Chrome extension integration$q$, $q$Brings AI writing help directly into Gmail, Google Docs, ChatGPT and other web text fields.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Custom Personas$q$, $q$Define persistent tone, role or style presets the assistant applies consistently.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Hundreds of pre-built AI tools$q$, $q$Purpose-specific templates like blog writers, email responders and research assistants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$AI Personal Assistant (agent mode)$q$, $q$Autonomously drives the browser to complete multi-step tasks like research and document creation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Citations and real-time information$q$, $q$Premium and Ultra tiers can ground responses with current web information and sources.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Autocomplete works inline across most web text fields via the Chrome extension, not just inside a dedicated app.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Large library of pre-built, task-specific AI tools reduces prompt-writing effort.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Agent mode can complete multi-step browser tasks, going beyond pure text generation.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Backed by a funded startup with its own model research track record, including Reflection 70B.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Free tier lets users try TypeAhead and basic features before committing to a paid plan.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Free tier is limited compared to some paid competitors' free offerings.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Message caps on the Premium tier, 250 per month, can be restrictive for heavy users; unlimited usage requires the pricier Ultra plan.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Smaller company than category leaders like Grammarly, which may mean fewer enterprise features and integrations.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Agent and task-automation features are newer and less proven than the core writing assistant.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Pricing is per-individual-seat oriented, without clearly published team or enterprise plans on the main pricing page.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Is HyperWrite free to use?$q$, $q$HyperWrite offers a free tier with limited features; full access to unlimited TypeAheads and more AI messages requires the Premium or Ultra paid plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$How much does HyperWrite cost?$q$, $q$Premium is $19.99/month, or $16/month billed annually, and Ultra is $44.99/month, or $29/month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Who built HyperWrite?$q$, $q$HyperWrite is built by OthersideAI, founded in New York in 2020 by Matt Shumer, Jason Kuperberg and Miles Feldstein.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Does HyperWrite work outside of its own app?$q$, $q$Yes, its Chrome extension brings autocomplete and chat assistance into Gmail, Google Docs, ChatGPT and most other web text fields.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$What is HyperWrite's AI Personal Assistant?$q$, $q$It is an agent mode that can autonomously use the browser to complete multi-step tasks, such as researching a topic and drafting a document.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Has OthersideAI built its own AI models?$q$, $q$Yes, the company released Reflection 70B, an open-source large language model, in 2024.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Everyday email and document writing$q$, $q$Professionals use HyperWrite's browser-wide autocomplete and chat assistant to draft emails, docs and messages faster inside the tools they already use.$q$, $q$Professionals and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Marketing and content creation$q$, $q$Marketers and creators use HyperWrite's pre-built tools to generate blog posts, social captions and SEO content at scale.$q$, $q$Marketers and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Research and task automation$q$, $q$Students and researchers use HyperWrite's Scholar AI tool and agent mode to search topics, summarize sources and compile findings into documents.$q$, $q$Students and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Limited AI messages","Basic TypeAhead access","Access to core writing tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Premium$q$, $q$$19.99/month ($16/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["250 AI messages/month","Citations and real-time info","3 custom personas","Hundreds of AI tools","Unlimited TypeAheads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Ultra$q$, $q$$44.99/month ($29/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited AI messages","10 custom personas","Unlimited TypeAheads","First access to experimental features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HyperWrite is an AI writing assistant and browser-based AI agent built by OthersideAI, a New York company founded in 2020 by Matt Shumer, Jason Kuperberg and Miles Feldstein. It launched in July 2020 around TypeAhead, an inline autocomplete feature that suggests the rest of a sentence as gray text a user accepts with Tab.$q$, $q$OthersideAI raised a $2.8 million seed round in March 2023 led by Madrona Venture Group, bringing total disclosed funding to roughly $5.4 million, and later drew attention in the AI research community for releasing Reflection 70B, an open-source large language model tuned with a reflection-tuning technique.$q$, $q$The product has grown from a pure autocomplete tool into a fuller AI assistant spanning a web app, a Chrome extension, and an agent mode that can take actions in the browser on a user's behalf.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$TypeAhead autocomplete and an AI chat assistant work directly inside Gmail, Google Docs, ChatGPT and most other web text fields through HyperWrite's Chrome extension, so users do not need to copy text in and out of a separate app.$q$, $q$Custom Personas let users define a persistent tone, role or writing style the assistant should consistently apply, while a library of hundreds of pre-built AI tools covers specific use cases like SEO blog writing, email responses and academic research.$q$, $q$The AI Personal Assistant, or agent mode, goes beyond text generation: it can autonomously drive the browser through multi-step tasks, such as researching a topic, opening a document and pasting in a summary, without the user performing each step manually.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HyperWrite runs on a freemium model. The free tier offers limited AI messages and basic TypeAhead access, while Premium costs $19.99 per month, or $16 per month billed annually, and includes 250 AI messages per month, citations with real-time information, three custom personas and unlimited TypeAheads.$q$, $q$The Ultra tier costs $44.99 per month, or $29 per month billed annually, and removes the AI message cap entirely, expands custom personas to ten, and grants first access to experimental features such as new agent capabilities.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Distributed, censorship-resistant storage$q$, $q$Files are split, encrypted and spread redundantly across participating nodes with no central server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Freesites$q$, $q$Static websites published to the network that cannot be taken down by targeting a single host.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Opennet and darknet modes$q$, $q$Connect to the wider public network or restrict connections to manually trusted friends for higher resistance to infiltration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Anonymous publishing and browsing$q$, $q$Strong encryption and key-based routing protect both publishers and readers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Updatable content via Signed Subspace Keys$q$, $q$Publishers can update freesites over time using cryptographic subspace keys.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Built-in forums and messaging$q$, $q$Community tools for anonymous discussion layered on top of the core network.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Community-driven development$q$, $q$Fully open-source, volunteer-maintained under GPLv3 with no corporate ownership.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Completely free, open-source and free of any corporate or advertising business model.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Long track record dating back to 1999, with peer-reviewed academic research behind its design.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Darknet mode offers strong resistance to network infiltration and traffic analysis via friend-to-friend connections.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$No single point of failure or control, making published content genuinely difficult to censor or take down.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Active, transparent open-source development with code available on GitHub.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Requires running dedicated node software and contributing disk space and bandwidth, unlike simply visiting a website.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Smaller user base than Tor or mainstream VPNs means slower content retrieval and less content overall.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$The 2023 rename from Freenet to Hyphanet has caused ongoing naming confusion with an unrelated newer Freenet project.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Steeper learning curve for non-technical users compared to browser-based anonymity tools.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$No official support organization or SLA since it is a volunteer community project.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Is Hyphanet the same as Freenet?$q$, $q$Yes, Hyphanet is the renamed continuation of the original Freenet project, rebranded in mid-2023; a separate, unrelated project now uses the Freenet name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Who created Hyphanet?$q$, $q$Ian Clarke created the original Freenet as a student project at the University of Edinburgh in 1999.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Is Hyphanet free to use?$q$, $q$Yes, Hyphanet is free, open-source software released under the GNU General Public License version 3.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$How does Hyphanet protect anonymity?$q$, $q$It encrypts and splits content across a distributed network of user-run nodes, using cryptographic keys for routing so no single node knows the full picture of who published or requested content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$What is the difference between opennet and darknet mode?$q$, $q$Opennet connects automatically to other Hyphanet users for ease of use, while darknet only connects to manually added, trusted friends for stronger resistance to surveillance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$What can you do on Hyphanet?$q$, $q$Users can publish censorship-resistant static websites called freesites, participate in anonymous forums and messaging, and share files without relying on a central server.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Censorship-resistant publishing$q$, $q$Journalists and activists in restrictive environments publish freesites that cannot be taken down by pressuring a single host or ISP.$q$, $q$Journalists and activists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Anonymous research and communication$q$, $q$Privacy-conscious individuals and researchers use Hyphanet for anonymous forums, messaging and file sharing outside of centralized platforms.$q$, $q$Privacy researchers and privacy-focused users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Decentralized systems study$q$, $q$Computer science students and researchers study Hyphanet's routing and distributed storage design as a foundational example of anonymous P2P networking.$q$, $q$Academic and computer science researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full node software for desktop operating systems","Unlimited freesite publishing","Opennet and darknet connectivity modes","Community support via forums, GitHub and mailing lists"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$Support the Project (Optional Donation)$q$, $q$Pay what you want$q$, $q$One-time or recurring$q$, NULL, $q$["Not required to use the network","Voluntary donations fund ongoing development","No additional features unlocked","Community-run, non-commercial project"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hyphanet is a free, open-source peer-to-peer network for censorship-resistant, anonymous publishing and communication. It is the direct continuation of the Freenet project, renamed in mid-2023, and traces its origins to 1999, when Ian Clarke designed the system as a student project at the University of Edinburgh.$q$, $q$Clarke and collaborators formalized the design in a widely cited 2001 academic paper, and the network moved into practical use around 2000, making Hyphanet one of the oldest anonymous peer-to-peer systems still actively maintained today.$q$, $q$There is no company behind Hyphanet. It is developed by a volunteer, open-source community and has never taken venture funding or operated as a commercial product; its software is released under the GNU General Public License version 3.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hyphanet works as a decentralized distributed data store: every node contributes disk space and bandwidth to the network, and files are split into encrypted blocks and distributed redundantly across many nodes rather than hosted on a single server.$q$, $q$Content is addressed with cryptographic keys, Content Hash Keys for static content and Signed Subspace Keys for content a publisher wants to update over time, enabling freesites, static websites that cannot be taken down by targeting one host.$q$, $q$Two connectivity modes serve different needs: opennet connects automatically to other users for ease of use, while darknet restricts connections to manually added, trusted friends, trading convenience for stronger resistance to surveillance and infiltration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hyphanet is entirely free to download and run. There is no subscription, license fee or paid tier; users only need to install the Java-based node software and contribute some local disk space and bandwidth to participate in the network.$q$, $q$The project accepts voluntary donations to support ongoing development, but donating is optional and does not unlock any additional features, consistent with Hyphanet's identity as a non-commercial, community-run project.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
