INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e4e15aa2-1586-4029-bdbb-ccdc26761466', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Bulk product description generation$q$, $q$Create SEO-ready product copy at catalog scale from attributes or images.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Multi-language content$q$, $q$Generate content in 30+ languages for international ecommerce catalogs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Product attribute enrichment$q$, $q$Automatically structure and tag raw catalog data into a usable taxonomy.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$AI bulk image editor$q$, $q$Edit and generate product imagery across large catalogs at once.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Brand and channel guideline checker$q$, $q$AI flags content that deviates from a brand's style or channel requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$SEO content generation$q$, $q$Category pages, meta titles and descriptions, and blog articles optimized for search.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$PIM and ERP integrations$q$, $q$Connect to enterprise product-information and resource-planning systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Marketing copy generation$q$, $q$Ad copy, product taglines and general marketing content beyond product listings.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Purpose-built for ecommerce catalogs rather than generic blog or marketing copy alone.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Supports both content generation and underlying product-data enrichment and tagging in one platform.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Strong multi-language support suited to international ecommerce brands.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Self-serve Marketing plans offer an accessible entry point before committing to enterprise ecommerce pricing.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Backed by Y Combinator with founders bringing Amazon and Stripe product and AI experience.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Ecommerce-tier pricing is not fully published and often requires a sales conversation.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Ecommerce Basic and Pro pricing, reportedly $150-$500+ per month, is a step up from cheaper general-purpose AI writing tools.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Smaller team, around 20 employees, than larger AI content platforms like Jasper.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Bulk AI-generated content still typically needs human review for brand voice accuracy at scale.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Feature set spans both content and PIM functions, which may be more than smaller sellers actually need.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$What does Hypotenuse AI do?$q$, $q$Hypotenuse AI generates product descriptions, marketing copy and SEO content for ecommerce brands, and also enriches and structures underlying product data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$How much does Hypotenuse AI cost?$q$, $q$Marketing plans start at $29/month, or $19/month billed annually, for 50,000 words; ecommerce plans start around $150/month for small catalogs, with custom Enterprise pricing for larger brands.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Who founded Hypotenuse AI?$q$, $q$Hypotenuse AI was founded in Singapore in 2020 by Joshua Wong and Low Lin-Hui, through Y Combinator's Summer 2020 batch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$How many languages does Hypotenuse AI support?$q$, $q$Hypotenuse AI supports content generation in more than 30 languages, depending on the plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Does Hypotenuse AI integrate with PIM systems?$q$, $q$Yes, Enterprise ecommerce customers can connect Hypotenuse AI to their PIM and ERP systems for catalog-wide content and data workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Is Hypotenuse AI only for product descriptions?$q$, $q$No, beyond product descriptions it also generates blog articles, category pages and ad copy, and supports bulk image editing and product attribute enrichment.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Ecommerce catalog content at scale$q$, $q$Retail and ecommerce brands generate consistent, SEO-optimized product descriptions across thousands of SKUs instead of writing each one manually.$q$, $q$Ecommerce merchandising and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$SEO and marketing content production$q$, $q$Marketers use the self-serve Marketing plans to generate blog posts, meta descriptions and ad copy in a fraction of the time of manual writing.$q$, $q$Marketing and SEO teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Product data enrichment for large catalogs$q$, $q$Enterprise retailers use attribute enrichment and tagging to clean up and structure messy or incomplete product catalog data.$q$, $q$Enterprise ecommerce and product data teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Marketing Entry$q$, $q$$29/month ($19/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["50,000 words/month","1 user seat","SEO content generation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Marketing Pro$q$, $q$$87/month ($56/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["250,000 words/month","1 user seat","Advanced SEO features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Ecommerce Basic$q$, $q$From approximately $150/month$q$, $q$Monthly$q$, NULL, $q$["1 seat","Product description generator","20+ ecommerce content types","30+ languages","Catalogs under 100 products"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Ecommerce Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Custom seats","Product attribute enrichment","Bulk AI image editor","Brand guideline checker","Custom PIM/ERP integrations","Dedicated account manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hypotenuse AI is an AI-native content and product-data platform built for ecommerce brands and marketing teams. It was founded in Singapore in 2020 by Joshua Wong and Low Lin-Hui through Y Combinator's Summer 2020 batch, and has grown into a distributed team of roughly 20 people across Asia, North America and Europe.$q$, $q$The product has evolved from a straightforward AI copywriting tool into what the company describes as an AI-native product experience management platform, reflecting a shift toward managing structured product data and imagery alongside marketing text.$q$, $q$Hypotenuse AI serves customers ranging from solo ecommerce sellers on its self-serve plans to Fortune 500 retail brands managing large product catalogs on its Enterprise tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Hypotenuse AI generates bulk product descriptions, category pages, meta titles and blog articles from structured product attributes or images, supporting more than 30 languages for international catalogs.$q$, $q$On the data side, it offers product attribute enrichment and automated tagging that structures raw catalog data into a usable taxonomy, a bulk AI image editor for adjusting product imagery at scale, and an AI brand and channel guideline checker that flags content deviating from a company's style guide.$q$, $q$Enterprise customers can connect Hypotenuse AI to their PIM and ERP systems, giving large retailers a way to generate and manage content directly against their existing product-data infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hypotenuse AI splits pricing across two tracks. Self-serve Marketing and SEO plans start at $29 per month, $19 per month billed annually, for 50,000 words, rising to $87 per month, $56 per month billed annually, for 250,000 words on the Pro plan.$q$, $q$Ecommerce plans are aimed at catalog-scale customers: a Basic tier runs roughly $150 per month for catalogs under 100 products, a Pro tier starts around $500 per month for larger catalogs with advanced SEO features, and an Enterprise tier offers fully custom pricing for large teams with strict brand-guideline and integration needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
