INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Centralized, real-time PDF repository$q$, $q$A single searchable library shared across a team or institution instead of individual desktop libraries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Integrated academic and patent database search$q$, $q$Query Crossref, Scopus, ScienceDirect, PubMed, IEEE, NASA and a 100M+ patent database directly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$AI paper summaries and chat$q$, $q$Instantly summarize papers and query across an entire document collection in natural language.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$In-browser PDF viewer with annotations$q$, $q$Read, highlight and annotate PDFs without leaving the browser.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$OCR support$q$, $q$Extract searchable text from scanned documents.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Self-hosted deployment option$q$, $q$Run I, Librarian on-premises behind an organization's own firewall for full data control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$SSO authentication$q$, $q$Institutional single sign-on for managed, secure access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Boolean and full-text search$q$, $q$Advanced search built for systematic literature reviews.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Genuine open-source, self-hostable Community Edition gives full data ownership at no licensing cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Centralized, multi-user repository model suits institutional and team research settings better than single-user reference managers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Broad integrated database search spanning academic literature and patents in one place.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Built-in AI summarization and cross-library chat are unusual among self-hostable reference managers.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Flexible pricing, per-user, per-GB, or one-time perpetual license, fits both small labs and larger institutions.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Less mainstream and smaller community than Zotero or Mendeley, meaning fewer third-party integrations and browser plugins.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$AI features and access to premium databases like Scopus and ScienceDirect are gated behind the Pro tier.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Self-hosted deployment requires technical setup and container management, unlike a fully managed SaaS.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Pricing structure combining a base fee, per-user cost and per-GB storage can be harder to estimate upfront than flat per-seat pricing.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Smaller company with a leaner support team than larger reference-management vendors.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Is I, Librarian open source?$q$, $q$Yes, a free Community Edition is available on GitHub for self-hosting; commercial cloud and self-hosted Pro tiers add AI features and premium database access.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$How much does I, Librarian cost?$q$, $q$The cloud Lite plan starts at $2/month plus $1.50 per user and $0.50/GB storage; Pro starts at $3/month plus $2.50 per user; self-hosted Pro licenses run $36/year per user or $126 per user as a one-time perpetual license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Who makes I, Librarian?$q$, $q$I, Librarian is developed by Scilico, LLC, a Dallas, Texas-based software company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Can I, Librarian search academic databases directly?$q$, $q$Yes, it integrates search across Crossref, Scopus, ScienceDirect, PubMed, PubMed Central, IEEE, NASA and a large patent database.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Does I, Librarian have AI features?$q$, $q$Yes, its Pro tier includes AI-generated paper summaries and AI chat for querying across a user's entire document library.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Can I, Librarian be self-hosted?$q$, $q$Yes, both a free open-source Community Edition and a paid Pro Self-Hosted license are available for on-premises deployment.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Institutional reference libraries$q$, $q$Universities and research institutions centralize thousands of papers into one searchable, multi-user repository instead of scattered individual libraries.$q$, $q$Universities and academic libraries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Systematic literature reviews$q$, $q$Researchers use Boolean and full-text search across integrated academic databases to conduct rigorous, reproducible literature reviews.$q$, $q$Academic and clinical researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Self-hosted, privacy-sensitive research$q$, $q$Healthcare and biotech organizations self-host I, Librarian on-premises to keep proprietary research data fully under their own control.$q$, $q$Healthcare and biotech R and D teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Community Edition (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source self-hosted deployment","PDF organization","Basic search","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Lite (Cloud)$q$, $q$From $2/month + $1.50/user + $0.50/GB$q$, $q$Monthly$q$, NULL, $q$["PDF organization","In-browser viewer with annotations","Full-text search","Arxiv, Crossref, IEEE, NASA, PubMed search","OCR","SSO","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Pro (Cloud)$q$, $q$From $3/month + $2.50/user + $0.50/GB$q$, $q$Monthly$q$, NULL, $q$["Everything in Lite","AI chat and summaries","AI literature discovery","ScienceDirect, Scopus and patent database search","Offline export","Audio notes","Activity logs"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$Pro Self-Hosted$q$, $q$$36/year per user or $126/user one-time$q$, $q$Annual or perpetual license$q$, NULL, $q$["Full Pro functionality on-premises","Data sovereignty","Unlimited libraries","Container-based deployment","Optional email support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$I, Librarian is a reference and PDF management platform for researchers and institutions, developed by Scilico, LLC, a Dallas, Texas-based software company that has focused on scientific and technical software since around 2015.$q$, $q$It is available as a free, open-source, self-hostable Community Edition distributed on GitHub, and as a commercially licensed cloud or self-hosted product with additional AI-powered features, giving organizations a choice between a fully free option and a paid, more capable one.$q$, $q$The platform is built around a single, centralized, real-time repository of PDFs and references that a whole team or institution can search and share, an explicit alternative to scattering references across individual researchers' local reference managers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can search across major scholarly and patent databases directly from within I, Librarian, including Crossref, Scopus, ScienceDirect, PubMed, PubMed Central, IEEE, NASA's database and a worldwide patent database exceeding 100 million records, alongside full-text and Boolean search of their own stored library.$q$, $q$Newer AI-powered features include instant AI-generated summaries of uploaded papers and AI chat that lets researchers query across their entire document collection in natural language, plus AI-generated text and note summaries within individual PDFs.$q$, $q$Other capabilities include an in-browser PDF viewer with annotation tools, OCR for scanned documents, single sign-on authentication for institutional deployments, offline app export, audio notes and activity logs for tracking team usage.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff47afbc-51e2-479e-9cbb-45a5ec96314e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free, open-source Community Edition can be self-hosted with no licensing cost, giving privacy-conscious teams full control of their data. The commercial cloud Lite plan starts at $2 per month plus $1.50 per additional user and $0.50 per GB of storage, while the Pro plan starts at $3 per month plus $2.50 per user and adds AI chat, AI summaries and access to premium databases like Scopus and ScienceDirect.$q$, $q$Organizations that need on-premises deployment behind their own firewall can choose a Pro Self-Hosted license, priced at $36 per year per user or $126 per user as a one-time perpetual license, delivered via container-based deployment with optional paid email support.$q$]::text[], 2);
