-- ── Hyperline ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Usage-based quote-to-cash billing platform helping B2B SaaS companies manage CPQ, invoicing, payments and revenue recognition.$q$, short_description),
  pricing_model = COALESCE($q$Subscription plus usage fee$q$, pricing_model),
  starting_price = COALESCE($q$$199/month + 0.6% of billed revenue$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hyperline Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hyperline is a quote-to-cash billing platform for B2B SaaS. Explore its CPQ, invoicing and usage-based billing features, pricing tiers and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hyperline is a quote-to-cash revenue management platform built specifically for B2B software companies that need to combine sales quoting, subscription billing, invoicing, payment collection and usage-based pricing in a single system rather than stitching together separate CPQ, billing and payments tools. The company was founded in Paris, France in 2022 by Lucas Bedout and Clement Garbay, and launched publicly in June 2023 with a EUR4 million seed round led by Index Ventures, with participation from Kima Ventures and the founders of Qonto, Spendesk and Primer. In January 2025 Hyperline announced a further $10 million seed extension, also led by Index Ventures with Adelie Capital participating, bringing the company's total disclosed funding to roughly $14.4 million. As of 2026 the team is reported to be in the 25-35 person range, having grown from around 14 employees in early 2025. Hyperline's product bundles four functional areas: configure-price-quote, or CPQ, with e-signature and approval workflows so sales teams can generate and close quotes without leaving the platform; billing and invoicing, including subscription management, tax calculation, dunning for failed payments, compliant invoicing and revenue recognition; payments, orchestrated across processors including Stripe, GoCardless, Mollie and Airwallex so companies are not locked into a single payment provider; and usage-based billing, with real-time consumption tracking, metered products, automated seat-based billing and prepaid credit management, aimed at the growing share of SaaS and infrastructure companies charging by usage rather than flat subscription fees. A customer portal, analytics and reporting, and support for international, multi-currency billing round out the platform. Hyperline publishes its pricing openly, which is relatively unusual among CPQ and billing vendors: the entry 'Quote to Cash' plan costs $199 per month plus 0.6 percent of billed revenue and covers subscriptions, CPQ, invoicing, payment collection, tax management, the customer portal, analytics and international billing, with a genuine self-serve free trial covering the first 10 invoices and no credit card required. A 'Quote to Cash + Usage' tier adds unlimited billing events, real-time consumption tracking, metered products, automated seat-based billing, prepaid credits and a direct database connection for $299 per month plus 0.7 percent of billed revenue. Companies doing more than $5 million in annual recurring revenue move to a custom 'Quote to Cash + High Volume' contract with unlimited invoices, premium support, and dedicated migration and historical-data-import assistance; both self-serve tiers can also add CRM and accounting-system integrations for an additional $50 per integration per month. Hyperline's target customers are venture-backed B2B SaaS and usage-based software companies, from early-stage startups outgrowing spreadsheets or basic invoicing tools, up to scale-ups with complex multi-product, multi-currency, usage-metered pricing models that need CPQ, billing and payments in one workflow instead of duct-taping together a CRM, a spreadsheet-based CPQ process, Stripe Billing and a separate revenue-recognition tool. In the crowded quote-to-cash and subscription-billing space, Hyperline positions itself against Chargebee, Recurly, Maxio, formerly Chargify and SaaSOptics, Stripe Billing, Zuora, and CPQ-adjacent tools like PandaDoc or DealHub, differentiating primarily on being purpose-built for modern usage-based and hybrid pricing models, bundling CPQ directly into the billing flow rather than treating it as a bolt-on, offering payment-processor flexibility instead of tying customers to a single PSP, and publishing transparent, revenue-percentage-based pricing rather than requiring a sales call for every tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd452fd91-6d49-40e7-8a71-ae9f6a9bbf92';

