-- ── HyperWrite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI writing assistant and browser agent from OthersideAI offering autocomplete, chat, custom personas and task automation.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HyperWrite Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HyperWrite is an AI writing assistant and browser agent from OthersideAI. See its 2026 features, pricing plans and top competing tools in this review.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HyperWrite is an AI-powered writing assistant and browser-based AI agent built by OthersideAI, a New York-based startup founded in 2020 by Matt Shumer, Jason Kuperberg and Miles Feldstein. The product launched in July 2020 with a mission the founders describe as using AI to help the world communicate more effectively, and it grew initially around a simple but sticky feature: an inline autocomplete called TypeAhead that suggests the rest of a sentence as subtle gray text a user can accept by pressing Tab, similar in spirit to code-completion tools but aimed at everyday writing in email, docs and web forms. OthersideAI raised a $2.8 million seed round in March 2023 led by Madrona Venture Group, with participation from Active Capital and individual angels including Siqi Chen and Aidan Gomez, bringing total disclosed funding to roughly $5.4 million. The company also drew industry attention in 2024 when it released Reflection 70B, an open-source large language model fine-tuned with a 'reflection tuning' technique, positioning OthersideAI and HyperWrite not just as an application-layer writing tool but as a company experimenting with its own model research. Functionally, HyperWrite today spans several surfaces: a web app and Chrome extension that brings AI autocomplete and an AI chat assistant into Gmail, Google Docs, ChatGPT and most text fields across the browser; a library of hundreds of pre-built, purpose-specific AI tools, for example an SEO-friendly blog post writer, an email responder, and a research-focused Scholar AI tool; custom Personas that let users define a persistent tone, role or writing style the assistant should adopt; and an AI Personal Assistant, or agent mode, that can autonomously drive the browser to complete multi-step tasks, such as searching a topic, opening a new document and pasting in a summary, without the user manually performing each step. HyperWrite operates on a freemium subscription model with two paid tiers plus a limited free tier. Premium costs $19.99 per month billed monthly, or $16 per month, $192 per year, billed annually, and includes 250 AI messages per month, citations with real-time information retrieval, three custom personas, access to the full library of pre-built AI tools, and unlimited TypeAhead autocomplete usage. Ultra costs $44.99 per month billed monthly, or $29 per month, $348 per year, billed annually, and adds unlimited AI messages, ten custom personas, unlimited TypeAheads, and first access to experimental features such as new agent capabilities. HyperWrite's target users are individual professionals, students, marketers, sales and support teams, and content creators who want an AI assistant embedded directly into their existing writing surfaces rather than a separate chat window they have to copy-paste in and out of. It competes with Jasper, Copy.ai, Grammarly, particularly Grammarly's newer generative features, Notion AI, and general-purpose assistants like ChatGPT and Google Gemini used for writing tasks, differentiating primarily through its always-on browser-level autocomplete and its evolution from a pure writing tool toward a browser-native AI agent that can take actions on a user's behalf rather than only generating text.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1e0af591-0b3b-4416-988d-d1b31d3ab630';

