  short_description = COALESCE($q$Open-source, decentralized peer-to-peer network for censorship-resistant, anonymous publishing and communication, formerly Freenet.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hyphanet Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hyphanet, formerly Freenet, is an open-source peer-to-peer network for censorship-resistant publishing. See its 2026 features, licensing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hyphanet is a free, open-source, peer-to-peer platform designed for censorship-resistant, anonymous publishing and communication, and is the direct continuation of the Freenet project, which it was renamed from in mid-2023. Its origins trace back to 1999, when Ian Clarke, then a student at the University of Edinburgh, designed the system as his graduation project with the stated goal of providing freedom of speech on the internet backed by strong anonymity protection; the project moved into practical use around 2000. Clarke and collaborators formalized the design in the influential 2001 paper 'Freenet: A Distributed Anonymous Information Storage and Retrieval System,' which went on to become one of the most frequently cited computer science papers of 2002 and helped establish Freenet as one of the earliest and most academically studied anonymous P2P networks, predating better-known privacy tools like Tor in public visibility. There is no company behind Hyphanet; it is developed and maintained by an open, volunteer community of contributors coordinated through the project's website, GitHub organization and mailing lists, and it has never taken venture funding or operated as a commercial product. Technically, Hyphanet works as a decentralized distributed data store: every user who runs a node contributes a portion of their own disk space and bandwidth to the network's shared datastore, and files are split into small blocks, encrypted, and distributed redundantly across many participating nodes rather than being hosted on any single server. Content is addressed and retrieved using cryptographic keys, primarily Content Hash Keys for static, immutable content and Signed Subspace Keys for content that a publisher wants to be able to update over time, such as a 'freesite.' The network supports two connectivity modes: opennet, where a node connects automatically to other, often unknown, Hyphanet users, prioritizing ease of use; and darknet, a friend-to-friend mode where a node only connects to peers the user has explicitly and manually added as trusted contacts, prioritizing resistance to traffic analysis and infiltration by leveraging small-world network routing efficiency along genuine social trust relationships. Layered on top of this storage-and-routing foundation is a suite of free software tools for publishing static websites, called freesites, that cannot be taken down because no single host serves them, forums and messaging systems, and file-sharing capabilities, all designed to work without any central point of control or failure that a censor could target. In 2023 the original project split its branding: the long-running Freenet codebase and community, with Ian Clarke's continued involvement, was renamed Hyphanet, while a separate, newer project retained the Freenet name for a different, unrelated peer-to-peer protocol, a distinction that is important for anyone researching the space post-2023, since documentation for the two is easily conflated. Hyphanet's software is released under the GNU General Public License version 3, consistent with its identity as fully free and open-source software; installation is free and available for major desktop operating systems, requiring only that a user run the Java-based node software and contribute local disk space to the network. Its target users are journalists, activists, whistleblowers, researchers and ordinary users operating in environments with internet censorship or surveillance concerns, as well as privacy researchers and free-software enthusiasts interested in decentralized systems generally. It sits alongside and is often compared to Tor, focused more on anonymous browsing and routing of conventional internet traffic, I2P, an anonymous overlay network with its own internal services, and IPFS, a distributed file system focused more on content addressing and efficiency than anonymity, with Hyphanet differentiating itself by combining anonymous publishing and long-term distributed storage in one system, and by predating most of these alternatives as one of the original censorship-resistant P2P networks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e4e15aa2-1586-4029-bdbb-ccdc26761466';

