-- ── I, Librarian ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source and cloud reference management platform for organizing, searching and AI-summarizing academic PDFs and citations.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (Open Source self-hosted plus paid cloud tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Dallas, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$I, Librarian Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$I, Librarian is an open-source reference manager with AI paper summaries and citation search. See its 2026 features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$I, Librarian is a reference and PDF management platform built for researchers, academic institutions and organizations that need to organize, search and analyze large collections of academic papers and documents, with a particular emphasis on privacy, data sovereignty and self-hosting. It is developed by Scilico, LLC, a Dallas, Texas-based software company that has focused on scientific and technical software since around 2015 and that maintains I, Librarian as both an open-source, self-hostable Community Edition and a commercially licensed cloud or self-hosted product. The platform works entirely through the browser, requiring no client software installation, and centers on a single, real-time, centralized repository of PDFs and references that a team or institution can search and share, rather than scattering references across individual researchers' local reference managers. Its feature set is built around integrated academic search across major scholarly and patent databases, letting users query and import records from sources including Crossref, Scopus, ScienceDirect, PubMed, PubMed Central, IEEE, NASA's database and a worldwide patent database exceeding 100 million records, alongside its own full-text and Boolean search across a user's stored library, aimed at supporting rigorous systematic literature reviews. More recent versions add AI-powered features: instant AI-generated summaries of uploaded papers, AI chat that lets researchers query across their entire document collection in natural language, and AI-generated text and note summaries within individual PDFs. Other capabilities include an in-browser PDF viewer with annotation tools, OCR for scanned documents, single sign-on authentication for institutional deployments, offline export of the app, audio notes, and activity logs for tracking usage across a team. I, Librarian is available in several tiers. A free, open-source Community Edition is distributed via GitHub for self-hosting at no cost, giving privacy-conscious users and smaller labs full control of their data without licensing fees. The commercial cloud product starts with a Lite plan at $2 per month base plus $1.50 per additional user and $0.50 per GB of storage, covering PDF organization, the in-browser viewer with annotations, full-text search, integrated search of Arxiv, Crossref, IEEE, NASA, PubMed and PubMed Central, OCR, SSO and email support. A Pro plan starts at $3 per month plus $2.50 per user and $0.50 per GB, adding AI chat and summaries, AI-powered literature discovery, integrated search of ScienceDirect, Scopus and the patent database, PDF text and note summaries, offline app export, audio notes and activity logs. For organizations that need on-premises deployment behind their own firewall, a Pro Self-Hosted license is available either as a $36 per year per user subscription or a $126 per user one-time perpetual license, delivered via container-based deployment with optional paid email support. Customers cited by the company include research-heavy organizations such as Imperial College London and biotech firms like Principia Biopharma, positioning I, Librarian's target audience as universities, healthcare and biotech companies, and engineering firms that need centralized, searchable, and often self-hosted reference libraries rather than individual desktop reference managers. It competes with Zotero, Mendeley, EndNote, JabRef and Papers, differentiating through its strong self-hosting and on-premises option for data-sovereignty-sensitive organizations, its centralized multi-user repository model, versus Zotero and Mendeley's more individual-library-centric design, and its built-in AI summarization and cross-library chat features layered directly into a self-hostable product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff47afbc-51e2-479e-9cbb-45a5ec96314e';

